        return await query.OrderBy(a => a.StartTime).ToListAsync();
    }

    public async Task<Appointment?> GetByIdAsync(int id)
    {
        return await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
            .FirstOrDefaultAsync(a => a.Id == id);
    }

    public async Task<bool> IsSlotAvailableAsync(DateTime start, DateTime end, int? excludeId = null)
    {
        var query = db.Appointments
            .Where(a => a.Status != AppointmentStatus.Cancelled)
            .Where(a => a.StartTime < end && a.EndTime > start);
        if (excludeId.HasValue)
            query = query.Where(a => a.Id != excludeId.Value);
        return !await query.AnyAsync();
    }

    public async Task<List<(DateTime Start, DateTime End)>> GetAvailableSlotsAsync(DateTime date)
    {
        var slots = new List<(DateTime, DateTime)>();
        var dayStart = date.Date.AddHours(8);
        var dayEnd = date.Date.AddHours(17);

        var existing = await db.Appointments
            .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
            .OrderBy(a => a.StartTime)
            .ToListAsync();

        var current = dayStart;
        while (current.AddMinutes(30) <= dayEnd)
        {
            var slotEnd = current.AddMinutes(30);
            var conflict = existing.Any(a => a.StartTime < slotEnd && a.EndTime > current);
            if (!conflict)
                slots.Add((current, slotEnd));
            current = current.AddMinutes(30);
        }
        return slots;
    }

    public async Task<Appointment> CreateAsync(Appointment appointment)
    {
        db.Appointments.Add(appointment);
        await db.SaveChangesAsync();
        return appointment;
    }

    public async Task UpdateAsync(Appointment appointment)
    {
        db.Appointments.Update(appointment);
        await db.SaveChangesAsync();
    }

    public async Task CancelAsync(int id)
    {
        var appt = await db.Appointments.FindAsync(id);
        if (appt != null)
        {
            appt.Status = AppointmentStatus.Cancelled;
            await db.SaveChangesAsync();
        }
    }
}

using Microsoft.EntityFrameworkCore;
using VetClinic.Data;
using VetClinic.Data.Models;

namespace VetClinic.Services;

public class BillingService(ApplicationDbContext db)
{
    public async Task<List<Invoice>> GetInvoicesAsync(InvoiceStatus? status = null)
    {
        var query = db.Invoices.Include(i => i.Pet).ThenInclude(p => p.Owner).AsQueryable();
        if (status.HasValue)
            query = query.Where(i => i.Status == status.Value);
        return await query.OrderByDescending(i => i.IssuedDate).ToListAsync();
    }

    public async Task<Invoice?> GetInvoiceByIdAsync(int id)
    {
        return await db.Invoices
            .Include(i => i.Pet).ThenInclude(p => p.Owner)
            .Include(i => i.LineItems)
            .Include(i => i.Payments.OrderByDescending(p => p.PaymentDate))
            .FirstOrDefaultAsync(i => i.Id == id);
    }

    public async Task<Invoice> CreateInvoiceAsync(Invoice invoice)
    {
        invoice.TotalAmount = invoice.LineItems.Sum(li => li.Quantity * li.UnitPrice);
        invoice.IssuedDate = DateTime.Now;
        invoice.DueDate ??= DateTime.Now.AddDays(30);
        db.Invoices.Add(invoice);
        await db.SaveChangesAsync();
        return invoice;
    }

    public async Task<Payment> ProcessPaymentAsync(Payment payment)
    {
        var invoice = await db.Invoices.FindAsync(payment.InvoiceId);
        if (invoice == null) throw new InvalidOperationException("Invoice not found");

        payment.PaymentDate = DateTime.Now;
        db.Payments.Add(payment);

        invoice.AmountPaid += payment.Amount;
        if (invoice.AmountPaid >= invoice.TotalAmount)
            invoice.Status = InvoiceStatus.Paid;
        else
            invoice.Status = InvoiceStatus.PartiallyPaid;

        await db.SaveChangesAsync();
        return payment;
    }

    public async Task<int> GetOutstandingInvoiceCountAsync()
    {
        return await db.Invoices.CountAsync(i => i.Status == InvoiceStatus.Pending || i.Status == InvoiceStatus.PartiallyPaid || i.Status == InvoiceStatus.Overdue);
    }
}

