                            var slotStart = day.AddHours(hour);
                            var slotEnd = slotStart.AddHours(1);
                            var slotAppts = appointments.Where(a => a.StartTime >= slotStart && a.StartTime < slotEnd).ToList();
                            <td class="@(slotAppts.Any() ? "table-info" : "")">
                                @foreach (var appt in slotAppts)
                                {
                                    <a href="appointments/edit/@appt.Id" class="d-block small text-decoration-none">
