@page "/"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@rendermode InteractiveServer

@inject PatientService PatientService
@inject AppointmentService AppointmentService
@inject BillingService BillingService

<PageTitle>Dashboard - VetClinic</PageTitle>

<h1>Dashboard</h1>

@if (loading)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="row mb-4">
        <div class="col-md-4">
            <div class="card text-bg-primary mb-3">
                <div class="card-body">
                    <h5 class="card-title">Today's Appointments</h5>
                    <p class="card-text display-4">@todayAppointments.Count</p>
                </div>
            </div>
        </div>
        <div class="col-md-4">
            <div class="card text-bg-success mb-3">
                <div class="card-body">
                    <h5 class="card-title">Total Patients</h5>
                    <p class="card-text display-4">@totalPatients</p>
                </div>
            </div>
        </div>
        <div class="col-md-4">
            <div class="card text-bg-warning mb-3">
                <div class="card-body">
                    <h5 class="card-title">Outstanding Invoices</h5>
                    <p class="card-text display-4">@outstandingInvoices</p>
                </div>
            </div>
        </div>
    </div>

    <div class="row">
        <div class="col-md-6">
            <h4>Today's Appointments</h4>
            @if (todayAppointments.Any())
            {
                <table class="table table-striped">
                    <thead><tr><th>Time</th><th>Pet</th><th>Reason</th><th>Status</th></tr></thead>
                    <tbody>
                        @foreach (var appt in todayAppointments)
                        {
                            <tr>
                                <td>@appt.StartTime.ToString("HH:mm")</td>
                                <td>@appt.Pet.Name</td>
                                <td>@appt.Reason</td>
                                <td><span class="badge bg-info">@appt.Status</span></td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted">No appointments scheduled for today.</p>
            }
        </div>
        <div class="col-md-6">
            <h4>Recent Patients</h4>
            @if (recentPatients.Any())
            {
                <table class="table table-striped">
                    <thead><tr><th>Name</th><th>Species</th><th>Owner</th></tr></thead>
                    <tbody>
                        @foreach (var pet in recentPatients)
                        {
                            <tr>
                                <td><a href="patients/details/@pet.Id">@pet.Name</a></td>
                                <td>@pet.Species</td>
                                <td>@pet.Owner.LastName</td>
                            </tr>
                        }
                    </tbody>
                </table>
            }
            else
            {
                <p class="text-muted">No patients registered yet.</p>
            }
        </div>
    </div>
}

@code {
    private bool loading = true;
    private List<Appointment> todayAppointments = new();
    private List<Pet> recentPatients = new();
    private int totalPatients;
    private int outstandingInvoices;

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var today = DateTime.Today;
            todayAppointments = await AppointmentService.GetAppointmentsAsync(today, today.AddDays(1));
            var allPets = await PatientService.GetAllPetsAsync();
            totalPatients = allPets.Count;
            recentPatients = allPets.Take(5).ToList();
            outstandingInvoices = await BillingService.GetOutstandingInvoiceCountAsync();
        }
        catch { }
        loading = false;
    }
}
ENDOFFILE

