    {
        try
        {
            if (selectedOwnerId == 0)
            {
                if (string.IsNullOrWhiteSpace(owner.FirstName) || string.IsNullOrWhiteSpace(owner.LastName))
                {
                    errorMessage = "Owner first and last name are required.";
                    return;
                }
                var newOwner = await PatientService.CreateOwnerAsync(owner);
                pet.OwnerId = newOwner.Id;
            }
            else
            {
                pet.OwnerId = selectedOwnerId;
            }

            if (string.IsNullOrWhiteSpace(pet.Name))
            {
                errorMessage = "Pet name is required.";
                return;
            }

            await PatientService.CreatePetAsync(pet);
            Nav.NavigateTo("patients");
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }
}
