                        <p><strong>Medications:</strong> @note.Medications</p>
                        @if (!string.IsNullOrEmpty(note.Notes))
                        {
                            <p><strong>Notes:</strong> @note.Notes</p>
                        }
                    </div>
                </div>
            }
        }
        else
        {
            <p class="text-muted">No treatment history yet.</p>
        }
    }
    else if (activeTab == "treatment")
    {
        <EditForm Model="newNote" OnValidSubmit="AddTreatmentNote" FormName="addNote">
            <div class="row">
                <div class="col-md-8">
                    <div class="mb-3">
                        <label class="form-label">Date</label>
                        <InputDate class="form-control" @bind-Value="newNote.Date" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Veterinarian Name</label>
                        <InputText class="form-control" @bind-Value="newNote.VeterinarianName" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Diagnosis</label>
                        <InputText class="form-control" @bind-Value="newNote.Diagnosis" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Treatment</label>
                        <InputText class="form-control" @bind-Value="newNote.Treatment" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Medications</label>
                        <InputText class="form-control" @bind-Value="newNote.Medications" />
                    </div>
                    <div class="mb-3">
                        <label class="form-label">Notes</label>
                        <InputTextArea class="form-control" @bind-Value="newNote.Notes" />
                    </div>
                    <button type="submit" class="btn btn-primary">Add Treatment Note</button>
                </div>
            </div>
        </EditForm>
    }
}

@code {
    [Parameter] public int Id { get; set; }

    private Pet? pet;
    private TreatmentNote newNote = new() { Date = DateTime.Today };
    private string activeTab = "details";
    private string? message;

    protected override async Task OnInitializedAsync()
    {
        pet = await PatientService.GetPetByIdAsync(Id);
    }

    private async Task UpdatePet()
    {
        if (pet != null)
        {
            await PatientService.UpdatePetAsync(pet);
            message = "Patient updated successfully.";
        }
    }

    private async Task AddTreatmentNote()
    {
        if (pet != null)
        {
            newNote.PetId = pet.Id;
            await PatientService.AddTreatmentNoteAsync(newNote);
            pet = await PatientService.GetPetByIdAsync(Id);
            newNote = new() { Date = DateTime.Today };
            message = "Treatment note added.";
            activeTab = "history";
        }
    }
}
