@page "/appointments"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@rendermode InteractiveServer

@inject AppointmentService AppointmentService
@inject NavigationManager Nav

<PageTitle>Appointments - VetClinic</PageTitle>

<h1>Appointments</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <label class="form-label">Week of:</label>
        <InputDate class="form-control" @bind-Value="weekStart" />
    </div>
    <div class="col-md-4 d-flex align-items-end">
        <button class="btn btn-outline-secondary me-2" @onclick="PreviousWeek">← Previous</button>
        <button class="btn btn-outline-secondary me-2" @onclick="NextWeek">Next →</button>
        <button class="btn btn-outline-primary" @onclick="LoadAppointments">Refresh</button>
    </div>
    <div class="col-md-4 text-end d-flex align-items-end justify-content-end">
        <a href="appointments/create" class="btn btn-primary">Book Appointment</a>
    </div>
</div>

@if (appointments == null)
{
    <p><em>Loading...</em></p>
}
else
{
    <div class="table-responsive">
        <table class="table table-bordered">
            <thead>
                <tr>
                    <th>Time</th>
                    @for (int i = 0; i < 7; i++)
                    {
                        var day = weekStart.AddDays(i);
                        <th>@day.ToString("ddd MM/dd")</th>
                    }
                </tr>
            </thead>
            <tbody>
                @for (int hour = 8; hour < 17; hour++)
                {
                    <tr>
                        <td><strong>@($"{hour:00}:00")</strong></td>
                        @for (int d = 0; d < 7; d++)
                        {
                            var day = weekStart.AddDays(d);
                            var slotStart = day.AddHours(hour);
                            var slotEnd = slotStart.AddHours(1);
                            var slotAppts = appointments.Where(a => a.StartTime >= slotStart && a.StartTime < slotEnd).ToList();
                            <td class="@(slotAppts.Any() ? "table-info" : "")">
                                @foreach (var appt in slotAppts)
                                {
                                    <a href="appointments/edit/@appt.Id" class="d-block small text-decoration-none">
                                        <strong>@appt.Pet.Name</strong><br/>
                                        <span class="badge bg-@GetStatusColor(appt.Status)">@appt.Status</span>
                                    </a>
                                }
                            </td>
                        }
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

@code {
    private DateTime weekStart = DateTime.Today.AddDays(-(int)DateTime.Today.DayOfWeek + (int)DayOfWeek.Monday);
    private List<Appointment>? appointments;

    protected override async Task OnInitializedAsync()
    {
        await LoadAppointments();
    }

    private async Task LoadAppointments()
    {
        var weekEnd = weekStart.AddDays(7);
        appointments = await AppointmentService.GetAppointmentsAsync(weekStart, weekEnd);
    }

    private void PreviousWeek()
    {
        weekStart = weekStart.AddDays(-7);
        _ = LoadAppointments();
    }

    private void NextWeek()
    {
        weekStart = weekStart.AddDays(7);
        _ = LoadAppointments();
    }

    private string GetStatusColor(AppointmentStatus status) => status switch
    {
        AppointmentStatus.Scheduled => "primary",
        AppointmentStatus.Completed => "success",
        AppointmentStatus.Cancelled => "secondary",
        _ => "info"
    };
}
ENDOFFILE

