@code {
    private Appointment appointment = new();
    private List<Pet>? pets;
    private DateTime selectedDate = DateTime.Today;
    private string selectedTime = "09:00";
    private int durationMinutes = 30;
    private string? errorMessage;
    private List<(DateTime Start, DateTime End)>? availableSlots;

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetAllPetsAsync();
        await CheckAvailability();
    }

    private async Task CheckAvailability()
    {
        availableSlots = await AppointmentService.GetAvailableSlotsAsync(selectedDate);
    }

    private void SelectSlot(DateTime start)
    {
        selectedTime = start.ToString("HH:mm");
    }

    private async Task HandleSubmit()
    {
        try
        {
            if (appointment.PetId == 0)
            {
                errorMessage = "Please select a patient.";
                return;
            }

            var timeParts = selectedTime.Split(':');
            appointment.StartTime = selectedDate.Date.AddHours(int.Parse(timeParts[0])).AddMinutes(int.Parse(timeParts[1]));
            appointment.EndTime = appointment.StartTime.AddMinutes(durationMinutes);

            var available = await AppointmentService.IsSlotAvailableAsync(appointment.StartTime, appointment.EndTime);
            if (!available)
            {
                errorMessage = "This time slot is not available. Please choose another time.";
                return;
            }

            await AppointmentService.CreateAsync(appointment);
            Nav.NavigateTo("appointments");
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }
}
