@page "/appointments/edit/{Id:int}"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@rendermode InteractiveServer

@inject AppointmentService AppointmentService
@inject NavigationManager Nav

<PageTitle>Edit Appointment - VetClinic</PageTitle>

@if (appointment == null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>Edit Appointment</h1>
    <p>Patient: <strong>@appointment.Pet.Name</strong> (Owner: @appointment.Pet.Owner.LastName)</p>

    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }
    @if (!string.IsNullOrEmpty(successMessage))
    {
        <div class="alert alert-success">@successMessage</div>
    }

    <div class="row">
        <div class="col-md-6">
            <EditForm Model="appointment" OnValidSubmit="HandleSubmit" FormName="editAppt">
                <div class="mb-3">
                    <label class="form-label">Date</label>
                    <InputDate class="form-control" @bind-Value="selectedDate" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Time</label>
                    <InputSelect class="form-control" @bind-Value="selectedTime">
                        @for (int h = 8; h < 17; h++)
                        {
                            <option value="@($"{h:00}:00")">@($"{h:00}:00")</option>
                            <option value="@($"{h:00}:30")">@($"{h:00}:30")</option>
                        }
                    </InputSelect>
                </div>
                <div class="mb-3">
                    <label class="form-label">Duration (minutes)</label>
                    <InputNumber class="form-control" @bind-Value="durationMinutes" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Reason</label>
                    <InputText class="form-control" @bind-Value="appointment.Reason" />
                </div>
                <div class="mb-3">
                    <label class="form-label">Status</label>
                    <InputSelect class="form-control" @bind-Value="appointment.Status">
                        @foreach (var s in Enum.GetValues<AppointmentStatus>())
                        {
                            <option value="@s">@s</option>
                        }
                    </InputSelect>
                </div>
                <div class="mb-3">
                    <label class="form-label">Notes</label>
                    <InputTextArea class="form-control" @bind-Value="appointment.Notes" />
                </div>
                <button type="submit" class="btn btn-primary">Save Changes</button>
                <button type="button" class="btn btn-danger ms-2" @onclick="CancelAppointment">Cancel Appointment</button>
                <a href="appointments" class="btn btn-secondary ms-2">Back</a>
            </EditForm>
        </div>
    </div>
}

@code {
    [Parameter] public int Id { get; set; }

    private Appointment? appointment;
    private DateTime selectedDate;
    private string selectedTime = "09:00";
    private int durationMinutes = 30;
    private string? errorMessage;
    private string? successMessage;

    protected override async Task OnInitializedAsync()
    {
        appointment = await AppointmentService.GetByIdAsync(Id);
        if (appointment != null)
        {
            selectedDate = appointment.StartTime.Date;
            selectedTime = appointment.StartTime.ToString("HH:mm");
            durationMinutes = (int)(appointment.EndTime - appointment.StartTime).TotalMinutes;
        }
    }

    private async Task HandleSubmit()
    {
        if (appointment == null) return;
        try
        {
            var timeParts = selectedTime.Split(':');
            appointment.StartTime = selectedDate.Date.AddHours(int.Parse(timeParts[0])).AddMinutes(int.Parse(timeParts[1]));
            appointment.EndTime = appointment.StartTime.AddMinutes(durationMinutes);

            var available = await AppointmentService.IsSlotAvailableAsync(appointment.StartTime, appointment.EndTime, appointment.Id);
            if (!available)
            {
                errorMessage = "This time slot is not available.";
                return;
            }

            await AppointmentService.UpdateAsync(appointment);
            successMessage = "Appointment updated successfully.";
            errorMessage = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private async Task CancelAppointment()
    {
        if (appointment == null) return;
        await AppointmentService.CancelAsync(appointment.Id);
        Nav.NavigateTo("appointments");
    }
}
ENDOFFILE

