5. namespace VetClinic.Services;
6. 
7. public class AppointmentService(ApplicationDbContext db)
8. {
9.     public async Task<List<Appointment>> GetAppointmentsAsync(DateTime? from = null, DateTime? to = null)
10.     {
11.         var query = db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner).AsQueryable();
12.         if (from.HasValue)
13.             query = query.Where(a => a.StartTime >= from.Value);
14.         if (to.HasValue)
15.             query = query.Where(a => a.StartTime <= to.Value);
16.         return await query.OrderBy(a => a.StartTime).ToListAsync();
17.     }
18. 
19.     public async Task<Appointment?> GetByIdAsync(int id)
20.     {
21.         return await db.Appointments.Include(a => a.Pet).ThenInclude(p => p.Owner)
22.             .FirstOrDefaultAsync(a => a.Id == id);
23.     }
24. 
25.     public async Task<bool> IsSlotAvailableAsync(DateTime start, DateTime end, int? excludeId = null)
26.     {
27.         var query = db.Appointments
28.             .Where(a => a.Status != AppointmentStatus.Cancelled)
29.             .Where(a => a.StartTime < end && a.EndTime > start);
30.         if (excludeId.HasValue)
31.             query = query.Where(a => a.Id != excludeId.Value);
32.         return !await query.AnyAsync();
33.     }
34. 
35.     public async Task<List<(DateTime Start, DateTime End)>> GetAvailableSlotsAsync(DateTime date)
36.     {
37.         var slots = new List<(DateTime, DateTime)>();
38.         var dayStart = date.Date.AddHours(8);
39.         var dayEnd = date.Date.AddHours(17);
40. 
41.         var existing = await db.Appointments
42.             .Where(a => a.StartTime.Date == date.Date && a.Status != AppointmentStatus.Cancelled)
43.             .OrderBy(a => a.StartTime)
44.             .ToListAsync();
45. 
46.         var current = dayStart;
47.         while (current.AddMinutes(30) <= dayEnd)
48.         {
49.             var slotEnd = current.AddMinutes(30);
50.             var conflict = existing.Any(a => a.StartTime < slotEnd && a.EndTime > current);
51.             if (!conflict)
52.                 slots.Add((current, slotEnd));
53.             current = current.AddMinutes(30);
54.         }
55.         return slots;
56.     }
57. 
58.     public async Task<Appointment> CreateAsync(Appointment appointment)
59.     {
60.         db.Appointments.Add(appointment);
61.         await db.SaveChangesAsync();
62.         return appointment;
63.     }
