72.     {
73.         var appt = await db.Appointments.FindAsync(id);
74.         if (appt != null)
75.         {
76.             appt.Status = AppointmentStatus.Cancelled;
77.             await db.SaveChangesAsync();
78.         }
79.     }
80. }
