 @page "/patients/register"
 @using Microsoft.AspNetCore.Authorization
 @using VetClinic.Data.Models
 @using VetClinic.Services
 @attribute [Authorize]
 @rendermode InteractiveServer

 @inject PatientService PatientService
 @inject NavigationManager Nav

 <PageTitle>Register Patient - VetClinic</PageTitle>

 <h1>Register New Patient</h1>

 @if (!string.IsNullOrEmpty(errorMessage))
 {
     <div class="alert alert-danger">@errorMessage</div>
 }

 <div class="row">
     <div class="col-md-6">
         <h4>Pet Information</h4>
         <EditForm Model="pet" OnValidSubmit="HandleSubmit" FormName="registerPet">
             <DataAnnotationsValidator />
             <div class="mb-3">
                 <label class="form-label">Name</label>
                 <InputText class="form-control" @bind-Value="pet.Name" />
             </div>
             <div class="mb-3">
                 <label class="form-label">Species</label>
                 <InputSelect class="form-control" @bind-Value="pet.Species">
                     <option value="">Select...</option>
                     <option value="Dog">Dog</option>
                     <option value="Cat">Cat</option>
                     <option value="Bird">Bird</option>
                     <option value="Rabbit">Rabbit</option>
                     <option value="Reptile">Reptile</option>
                     <option value="Other">Other</option>
                 </InputSelect>
             </div>
             <div class="mb-3">
                 <label class="form-label">Breed</label>
                 <InputText class="form-control" @bind-Value="pet.Breed" />
             </div>
             <div class="mb-3">
                 <label class="form-label">Date of Birth</label>
                 <InputDate class="form-control" @bind-Value="pet.DateOfBirth" />
             </div>
             <div class="mb-3">
                 <label class="form-label">Weight (kg)</label>
                 <InputNumber class="form-control" @bind-Value="pet.Weight" />
             </div>
             <div class="mb-3">
                 <label class="form-label">Microchip</label>
                 <InputText class="form-control" @bind-Value="pet.Microchip" />
             </div>

             <h4 class="mt-4">Owner Information</h4>
             <div class="mb-3">
                 <label class="form-label">Select Existing Owner</label>
                 <InputSelect class="form-control" @bind-Value="selectedOwnerId">
                     <option value="0">-- New Owner --</option>
                     @if (owners != null)
                     {
                         @foreach (var o in owners)
                         {
                             <option value="@o.Id">@o.FirstName @o.LastName</option>
                         }
                     }
                 </InputSelect>
             </div>

             @if (selectedOwnerId == 0)
             {
                 <div class="mb-3">
                     <label class="form-label">First Name</label>
                     <InputText class="form-control" @bind-Value="owner.FirstName" />
                 </div>
                 <div class="mb-3">
                     <label class="form-label">Last Name</label>
                     <InputText class="form-control" @bind-Value="owner.LastName" />
                 </div>
                 <div class="mb-3">
                     <label class="form-label">Phone</label>
                     <InputText class="form-control" @bind-Value="owner.Phone" />
                 </div>
                 <div class="mb-3">
                     <label class="form-label">Email</label>
                     <InputText class="form-control" @bind-Value="owner.Email" />
                 </div>
                 <div class="mb-3">
                     <label class="form-label">Address</label>
                     <InputText class="form-control" @bind-Value="owner.Address" />
                 </div>
             }

             <button type="submit" class="btn btn-primary">Register Patient</button>
             <a href="patients" class="btn btn-secondary ms-2">Cancel</a>
         </EditForm>
     </div>
 </div>

 @code {
     private Pet pet = new() { DateOfBirth = DateTime.Today };
     private Owner owner = new();
     private List<Owner>? owners;
     private int selectedOwnerId;
     private string? errorMessage;

     protected override async Task OnInitializedAsync()
     {
         owners = await PatientService.GetAllOwnersAsync();
     }

     private async Task HandleSubmit()
     {
         try
         {
             if (selectedOwnerId == 0)
             {
                 if (string.IsNullOrWhiteSpace(owner.FirstName) || string.IsNullOrWhiteSpace(owner.LastName))
                 {
                     errorMessage = "Owner first and last name are required.";
                     return;
                 }
                 var newOwner = await PatientService.CreateOwnerAsync(owner);
                 pet.OwnerId = newOwner.Id;
             }
             else
             {
                 pet.OwnerId = selectedOwnerId;
             }

             if (string.IsNullOrWhiteSpace(pet.Name))
             {
                 errorMessage = "Pet name is required.";
                 return;
             }

             await PatientService.CreatePetAsync(pet);
             Nav.NavigateTo("patients");
         }
         catch (Exception ex)
         {
             errorMessage = $"Error: {ex.Message}";
         }
     }
 }

