                                    <label class="form-label">Method</label>
                                    <InputSelect class="form-control" @bind-Value="payment.Method">
                                        @foreach (var m in Enum.GetValues<PaymentMethod>())
                                        {
                                            <option value="@m">@m</option>
                                        }
                                    </InputSelect>
                                </div>
                                <div class="col-md-4 mb-3">
                                    <label class="form-label">Reference</label>
                                    <InputText class="form-control" @bind-Value="payment.Reference" />
                                </div>
                            </div>
                            <button type="submit" class="btn btn-success">Process Payment</button>
                        </EditForm>
                    </div>
                </div>
            }

            @if (invoice.Payments.Any())
            {
                <div class="card">
                    <div class="card-header"><h5>Payment History</h5></div>
                    <div class="card-body">
                        <table class="table">
                            <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                            <tbody>
                                @foreach (var p in invoice.Payments)
                                {
                                    <tr>
                                        <td>@p.PaymentDate.ToString("yyyy-MM-dd HH:mm")</td>
                                        <td>$@p.Amount.ToString("F2")</td>
                                        <td>@p.Method</td>
                                        <td>@p.Reference</td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    </div>
                </div>
            }
        </div>
