@page "/billing/create"
@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@rendermode InteractiveServer

@inject BillingService BillingService
@inject PatientService PatientService
@inject NavigationManager Nav

<PageTitle>Create Invoice - VetClinic</PageTitle>

<h1>Create Invoice</h1>

@if (!string.IsNullOrEmpty(errorMessage))
{
    <div class="alert alert-danger">@errorMessage</div>
}

<div class="row">
    <div class="col-md-8">
        <EditForm Model="invoice" OnValidSubmit="HandleSubmit" FormName="createInvoice">
            <div class="mb-3">
                <label class="form-label">Patient</label>
                <InputSelect class="form-control" @bind-Value="invoice.PetId">
                    <option value="0">Select a patient...</option>
                    @if (pets != null)
                    {
                        @foreach (var pet in pets)
                        {
                            <option value="@pet.Id">@pet.Name (@pet.Owner.LastName)</option>
                        }
                    }
                </InputSelect>
            </div>
            <div class="mb-3">
                <label class="form-label">Description</label>
                <InputText class="form-control" @bind-Value="invoice.Description" />
            </div>
            <div class="mb-3">
                <label class="form-label">Due Date</label>
                <InputDate class="form-control" @bind-Value="dueDate" />
            </div>

            <h4 class="mt-4">Line Items</h4>
            <table class="table">
                <thead>
                    <tr><th>Description</th><th>Qty</th><th>Unit Price</th><th>Total</th><th></th></tr>
                </thead>
                <tbody>
                    @for (int i = 0; i < lineItems.Count; i++)
                    {
                        var index = i;
                        <tr>
                            <td><InputText class="form-control" @bind-Value="lineItems[index].Description" /></td>
                            <td style="width:80px"><InputNumber class="form-control" @bind-Value="lineItems[index].Quantity" /></td>
                            <td style="width:120px"><InputNumber class="form-control" @bind-Value="lineItems[index].UnitPrice" /></td>
                            <td>$@((lineItems[index].Quantity * lineItems[index].UnitPrice).ToString("F2"))</td>
                            <td><button type="button" class="btn btn-sm btn-outline-danger" @onclick="() => RemoveLineItem(index)">×</button></td>
                        </tr>
                    }
                </tbody>
            </table>
            <button type="button" class="btn btn-sm btn-outline-secondary mb-3" @onclick="AddLineItem">+ Add Line Item</button>

            <div class="mb-3">
                <strong>Total: $@lineItems.Sum(li => li.Quantity * li.UnitPrice).ToString("F2")</strong>
            </div>

            <button type="submit" class="btn btn-primary">Create Invoice</button>
            <a href="billing" class="btn btn-secondary ms-2">Cancel</a>
        </EditForm>
    </div>
</div>

@code {
    private Invoice invoice = new();
    private List<InvoiceLineItem> lineItems = new() { new InvoiceLineItem { Quantity = 1 } };
    private List<Pet>? pets;
    private DateTime dueDate = DateTime.Today.AddDays(30);
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        pets = await PatientService.GetAllPetsAsync();
    }

    private void AddLineItem()
    {
        lineItems.Add(new InvoiceLineItem { Quantity = 1 });
    }

    private void RemoveLineItem(int index)
    {
        if (lineItems.Count > 1)
            lineItems.RemoveAt(index);
    }

    private async Task HandleSubmit()
    {
        try
        {
            if (invoice.PetId == 0)
            {
                errorMessage = "Please select a patient.";
                return;
            }

            if (!lineItems.Any(li => !string.IsNullOrWhiteSpace(li.Description)))
            {
                errorMessage = "Please add at least one line item.";
                return;
            }

            invoice.LineItems = lineItems.Where(li => !string.IsNullOrWhiteSpace(li.Description)).ToList();
            invoice.DueDate = dueDate;
            await BillingService.CreateInvoiceAsync(invoice);
            Nav.NavigateTo("billing");
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }
}

