@using Microsoft.AspNetCore.Authorization
@using VetClinic.Data.Models
@using VetClinic.Services
@attribute [Authorize]
@rendermode InteractiveServer

@inject BillingService BillingService
@inject NavigationManager Nav

<PageTitle>Invoice Details - VetClinic</PageTitle>

@if (invoice == null)
{
    <p><em>Loading...</em></p>
}
else
{
    <h1>Invoice INV-@invoice.Id.ToString("D4")</h1>
    <p class="text-muted">
        Patient: <strong>@invoice.Pet.Name</strong> | Owner: @invoice.Pet.Owner.FirstName @invoice.Pet.Owner.LastName |
        Status: <span class="badge bg-@GetStatusColor(invoice.Status)">@invoice.Status</span>
    </p>

    @if (!string.IsNullOrEmpty(message))
    {
        <div class="alert alert-success">@message</div>
    }
    @if (!string.IsNullOrEmpty(errorMessage))
    {
        <div class="alert alert-danger">@errorMessage</div>
    }

    <div class="row">
        <div class="col-md-7">
            <div class="card mb-3">
                <div class="card-header"><strong>Invoice Details</strong></div>
                <div class="card-body">
                    <p><strong>Description:</strong> @invoice.Description</p>
                    <p><strong>Issued:</strong> @invoice.IssuedDate.ToString("yyyy-MM-dd")</p>
                    <p><strong>Due:</strong> @(invoice.DueDate?.ToString("yyyy-MM-dd") ?? "N/A")</p>

                    <table class="table table-sm">
                        <thead><tr><th>Item</th><th>Qty</th><th>Price</th><th>Total</th></tr></thead>
                        <tbody>
                            @foreach (var item in invoice.LineItems)
                            {
                                <tr>
                                    <td>@item.Description</td>
                                    <td>@item.Quantity</td>
                                    <td>$@item.UnitPrice.ToString("F2")</td>
                                    <td>$@((item.Quantity * item.UnitPrice).ToString("F2"))</td>
                                </tr>
                            }
                        </tbody>
                        <tfoot>
                            <tr><td colspan="3" class="text-end"><strong>Total:</strong></td><td><strong>$@invoice.TotalAmount.ToString("F2")</strong></td></tr>
                            <tr><td colspan="3" class="text-end"><strong>Paid:</strong></td><td><strong>$@invoice.AmountPaid.ToString("F2")</strong></td></tr>
                            <tr><td colspan="3" class="text-end"><strong>Balance:</strong></td><td><strong>$@((invoice.TotalAmount - invoice.AmountPaid).ToString("F2"))</strong></td></tr>
                        </tfoot>
                    </table>
                </div>
            </div>

            <div class="card mb-3">
                <div class="card-header"><strong>Payment History</strong></div>
                <div class="card-body">
                    @if (invoice.Payments.Any())
                    {
                        <table class="table table-sm">
                            <thead><tr><th>Date</th><th>Amount</th><th>Method</th><th>Reference</th></tr></thead>
                            <tbody>
                                @foreach (var payment in invoice.Payments)
                                {
                                    <tr>
                                        <td>@payment.PaymentDate.ToString("yyyy-MM-dd HH:mm")</td>
                                        <td>$@payment.Amount.ToString("F2")</td>
                                        <td>@payment.Method</td>
                                        <td>@payment.Reference</td>
                                    </tr>
                                }
                            </tbody>
                        </table>
                    }
                    else
                    {
                        <p class="text-muted">No payments recorded.</p>
                    }
                </div>
            </div>
        </div>

        <div class="col-md-5">
            @if (invoice.Status != InvoiceStatus.Paid)
            {
                <div class="card">
                    <div class="card-header"><strong>Process Payment</strong></div>
                    <div class="card-body">
                        <EditForm Model="newPayment" OnValidSubmit="ProcessPayment" FormName="processPayment">
                            <div class="mb-3">
                                <label class="form-label">Amount</label>
                                <InputNumber class="form-control" @bind-Value="newPayment.Amount" />
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Payment Method</label>
                                <InputSelect class="form-control" @bind-Value="newPayment.Method">
                                    @foreach (var m in Enum.GetValues<PaymentMethod>())
                                    {
                                        <option value="@m">@m</option>
                                    }
                                </InputSelect>
                            </div>
                            <div class="mb-3">
                                <label class="form-label">Reference</label>
                                <InputText class="form-control" @bind-Value="newPayment.Reference" />
                            </div>
                            <button type="submit" class="btn btn-success w-100">Process Payment</button>
                        </EditForm>
                    </div>
                </div>
            }
        </div>
    </div>

    <a href="billing" class="btn btn-secondary mt-3">Back to Invoices</a>
}

@code {
    [Parameter] public int Id { get; set; }

    private Invoice? invoice;
    private Payment newPayment = new();
    private string? message;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        invoice = await BillingService.GetInvoiceByIdAsync(Id);
        if (invoice != null)
            newPayment.Amount = invoice.TotalAmount - invoice.AmountPaid;
    }

    private async Task ProcessPayment()
    {
        if (invoice == null) return;
        try
        {
            if (newPayment.Amount <= 0)
            {
                errorMessage = "Payment amount must be greater than zero.";
                return;
            }

            newPayment.InvoiceId = invoice.Id;
            await BillingService.ProcessPaymentAsync(newPayment);
            invoice = await BillingService.GetInvoiceByIdAsync(Id);
            newPayment = new Payment { Amount = invoice!.TotalAmount - invoice.AmountPaid };
            message = "Payment processed successfully.";
            errorMessage = null;
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private string GetStatusColor(InvoiceStatus status) => status switch
    {
        InvoiceStatus.Pending => "warning",
        InvoiceStatus.PartiallyPaid => "info",
        InvoiceStatus.Paid => "success",
        InvoiceStatus.Overdue => "danger",
        _ => "secondary"
    };
}

