@attribute [Authorize]
@rendermode InteractiveServer

@inject BillingService BillingService
@inject NavigationManager Nav

<PageTitle>Billing - VetClinic</PageTitle>

<h1>Billing</h1>

<div class="row mb-3">
    <div class="col-md-6">
        <label class="form-label">Filter by Status</label>
        <InputSelect class="form-control" @bind-Value="selectedStatus">
            <option value="">All</option>
            @foreach (var s in Enum.GetValues<InvoiceStatus>())
            {
                <option value="@s">@s</option>
            }
        </InputSelect>
    </div>
    <div class="col-md-6 text-end d-flex align-items-end justify-content-end">
        <button class="btn btn-outline-primary me-2" @onclick="LoadInvoices">Refresh</button>
        <a href="billing/create" class="btn btn-primary">Create Invoice</a>
    </div>
